  font-size: clamp(2.1rem, 5vw, 3.2rem);
  letter-spacing: -0.032em;
  line-height: 1.05;
  color: var(--ink);
  margin-bottom: 0;
}

.hero-tagline blockquote {
  font-size: 1.08rem;
  color: var(--muted);
  border-left: 3px solid var(--accent);
  padding: 0.55rem 1rem;
  margin: 1.1rem 0 1.8rem;
}

.section-heading {
